		wordCount := len(words)
		readingTime := 0
		if wordCount > 0 {
			readingTime = int(math.Ceil(float64(wordCount) / 200.0))
		}
		e.Record.Set("word_count", wordCount)
		e.Record.Set("reading_time_minutes", readingTime)

